-- Precio de venta del equipo inicial de Pradera Dorada (los 35 items nivel 1 de clase).
UPDATE items SET buy_price = CASE slot
    WHEN 'WEAPON'    THEN 200
    WHEN 'OFFHAND'   THEN 200
    WHEN 'ARMOR'     THEN 180
    WHEN 'ACCESSORY' THEN 150
    ELSE 120
  END
  WHERE required_level = 1 AND class_id IS NOT NULL AND code LIKE '%_PRADERA';

