-- Mark class-zone equipment items as craftable
UPDATE items SET is_craftable = true WHERE
  (code LIKE '%_ARMOR_%' OR code LIKE '%_WEAPON_%' OR code LIKE '%_OFFHAND_%'
   OR code LIKE '%_HELMET_%' OR code LIKE '%_GLOVES_%' OR code LIKE '%_BOOTS_%')
  AND code NOT LIKE 'GUERRERO_WEAPON2H_%';

