-- ============================================================
-- SISTEMA DE LOGROS
-- ============================================================

-- Categoría de monstruo
ALTER TABLE monsters ADD COLUMN IF NOT EXISTS category TEXT NOT NULL DEFAULT 'BESTIA';

UPDATE monsters SET category='BESTIA'        WHERE code IN ('LOBO_PRADERA','LOBO_FEROZ','LOBO_HIELO','RATA_ALCANTARILLA','JABALI_HELADO','SALAMANDRA_ROJA');
UPDATE monsters SET category='INSECTOIDE'    WHERE code IN ('ARANA_VENENOSA');
UPDATE monsters SET category='HUMANOIDE'     WHERE code IN ('BANDIDO_CORRUPTO','BANDIDO_FUEGO','GOBLIN_SAQUEADOR','CHAMAN_OSCURO','CAPITAN_LOBOS','TITAN_PRADERA','BRUJO_MONTANA','MINERO_CORROMPIDO','ORCO_MONTANA','TROLL_SALVAJE','REY_MONTANA','SENOR_ACANTILADO','GIGANTE_HIELO','GIGANTE_NIEVE','CAZADOR_HIELO','BRUJA_CONGELADA','GUARDIAN_HIELO','PRINCIPE_HIELO','REY_HIELO','CAPITAN_PIRATA','PIRATA_SIN_NOMBRE','ARCHIMAGO_CORRUPTO','SACERDOTE_MALDITO','CENTINELA_ANTIGUO','GUARDIAN_ANCESTRAL','GUARDIAN_RUINAS');
UPDATE monsters SET category='DEMONIO'       WHERE code IN ('DEMONIO_LAVA','CENTINELA_INFERNAL','MAESTRO_LAVA','SENOR_CALDERA','TITAN_FUEGO','ENTIDAD_CORRUPTA_TEMPLO');
UPDATE monsters SET category='MUERTO_VIVIENTE' WHERE code IN ('MARINERO_MALDITO','CADAVER_REANIMADO','ZOMBIE_ANCIANO','ESQUELETO_GUERRERO','CENTINELA_MUERTE','LICH_ANCESTRAL','GUARDIAN_ABISMO','GRAN_ESQUELETO_ABISMO');
UPDATE monsters SET category='ESPECTRO'      WHERE code IN ('ESPECTRO_HELADO','ESPIRITU_CONGELADO','FANTASMA_ENCADENADO');
UPDATE monsters SET category='DRACOIDE'      WHERE code IN ('DRAGON_MENOR_CORRUPTO');
UPDATE monsters SET category='ELEMENTAL'     WHERE code IN ('ELEMENTAL_FUEGO','GUARDIAN_FUEGO_ANCESTRAL','GUARDIAN_HIELO_ANCESTRAL','GUARDIAN_AGUA_ANCESTRAL','CENTINELA_COSMICO','CENTINELA_PIEDRA');
UPDATE monsters SET category='ACUATICO'      WHERE code IN ('CANGREJO_GIGANTE','PIRANA_AGUA','BESTIA_PROFUNDIDADES','LEVIATAN_MENOR','SIRENA_CORRUPTA','SENOR_OCEANO');

-- Tabla de logros
CREATE TABLE IF NOT EXISTS achievements (
  id               SERIAL PRIMARY KEY,
  code             TEXT UNIQUE NOT NULL,
  name             TEXT NOT NULL,
  description      TEXT,
  condition_type   TEXT NOT NULL DEFAULT 'QUEST_COMPLETIONS',
  quest_id         INT REFERENCES quests(id) ON DELETE SET NULL,
  threshold        INT NOT NULL DEFAULT 100,
  bonus_type       TEXT,
  bonus_category   TEXT,
  bonus_stat       TEXT,
  bonus_percent    INT NOT NULL DEFAULT 0
);

-- Logros desbloqueados por jugador
CREATE TABLE IF NOT EXISTS player_achievements (
  id             SERIAL PRIMARY KEY,
  player_id      INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  achievement_id INT NOT NULL REFERENCES achievements(id),
  unlocked_at    TIMESTAMP NOT NULL DEFAULT now(),
  UNIQUE(player_id, achievement_id)
);
CREATE INDEX IF NOT EXISTS idx_player_achievements_player ON player_achievements(player_id);

