  ('ACH_CAZADOR_ARANAS','Cazador de Arañas','Las telarañas ya no son obstáculo para ti.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='PRADERA_COMUN_ARANA'),100,'DAMAGE_VS_CATEGORY','INSECTOIDE',5),
