  ('ACH_ASESINO_LOBOS','Asesino de Lobos','Has cazado tantos lobos que la manada te considera su depredador natural.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='PRADERA_CAZA_LOBO_FEROZ'),100,'DAMAGE_VS_CATEGORY','BESTIA',10),
  ('ACH_SENOR_PRADERA','Señor de la Pradera','Los animales de la pradera reconocen en ti a su verdadero depredador.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='PRADERA_DAILY_CACERIA_MANADA'),100,'DAMAGE_VS_CATEGORY','BESTIA',5),
  ('ACH_MATADOR_ORCOS','Matador de Orcos','Los orcos de la montaña prefieren evitarte.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='MONTANAS_COMUN_ORCO'),100,'DAMAGE_VS_CATEGORY','HUMANOIDE',5),
  ('ACH_CAZADOR_ESPECTROS','Cazador de Espectros','Tu voluntad es más fuerte que cualquier espectro.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='MONTANAS_COMUN_ESPECTRO'),100,'DAMAGE_VS_CATEGORY','ESPECTRO',5),
  ('ACH_ROMPE_TROLLS','Rompe-Trolls','Has derribado más trolls que ningún guerrero conocido.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='MONTANAS_COMUN_TROLL'),100,'DAMAGE_VS_CATEGORY','HUMANOIDE',5),
  ('ACH_PURIFICADOR_MINA','Purificador de la Mina','La corrupción no puede esconderse de ti.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='MONTANAS_COMUN_MINERO'),100,'DAMAGE_VS_CATEGORY','HUMANOIDE',5),
  ('ACH_CAZADOR_ESCAMAS','Cazador de Escamas','Las criaturas con escamas tiemblan ante tu presencia.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='VOLCAN_COMUN_SALAMANDRA'),100,'DAMAGE_VS_CATEGORY','BESTIA',5),
  ('ACH_EXORCISTA_MAGMA','Exorcista de Magma','Has enviado al inframundo más demonios de los que puedes contar.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='VOLCAN_COMUN_DEMONIO'),100,'DAMAGE_VS_CATEGORY','DEMONIO',10),
  ('ACH_VERDUGO_VOLCAN','Verdugo del Volcán','Los bandidos del volcán pagan el precio de cruzarte.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='VOLCAN_COMUN_BANDIDO_F'),100,'DAMAGE_VS_CATEGORY','HUMANOIDE',5),
  ('ACH_CONTRA_EL_CANTO','Contra el Canto','Eres inmune al encanto de las sirenas. Tus golpes también.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='COSTAS_COMUN_SIRENA'),100,'DAMAGE_VS_CATEGORY','ACUATICO',5),
  ('ACH_PESCADOR_LETAL','Pescador Letal','Cada criatura acuática que encuentras se convierte en tu presa.','QUEST_COMPLETIONS',(SELECT id FROM quests WHERE code='COSTAS_COMUN_PIRANA'),100,'DAMAGE_VS_CATEGORY','ACUATICO',5),
