-- EVO_PASSIVES_PATCH (idempotente: borra efectos temáticos previos antes de re-insertar)
DELETE FROM skill_effects
WHERE skill_id IN (
  SELECT s.id FROM skills s JOIN classes c ON c.id = s.class_id WHERE s.code LIKE '%_PASIVA_DON'
) AND stat_code IN (
  'PHYSICAL_DAMAGE','MAGICAL_DAMAGE','ELEMENTAL_DAMAGE','CRIT_DAMAGE',
  'GOLD_BONUS','XP_BONUS','DROP_RATE_BONUS','HEAL_BONUS','EVASION'
);

INSERT INTO skill_effects(skill_id, effect_type, stat_code, percent_amount, description)
  SELECT s.id, 'STAT_MOD', 'PHYSICAL_DAMAGE', 20, '+20% daño físico'
  FROM skills s JOIN classes c ON c.id = s.class_id
  WHERE c.code = 'BERSERKER' AND s.code LIKE '%_PASIVA_DON';
