-- ─── combat_abandoned_players ─────────────────────────────────────────────────
-- Registra jugadores que abandonaron un combate coop en curso (leave voluntario o kick).
-- penalized=TRUE → perdió 10% de oro; FALSE → fue expulsado por el líder (sin penalización).
-- El personaje del abandonado pasa a IA básica (ataque automático) para no trabar el combate.
CREATE TABLE IF NOT EXISTS combat_abandoned_players (
  session_id   INT NOT NULL REFERENCES combat_sessions(id) ON DELETE CASCADE,
  player_id    INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  penalized    BOOLEAN NOT NULL DEFAULT FALSE,
  abandoned_at TIMESTAMP NOT NULL DEFAULT now(),
  PRIMARY KEY (session_id, player_id)
);

