  (134::int,'Torre - Viento',FALSE::bool,3::int,NULL,NULL),
  (135::int,'Torre - Viento',FALSE::bool,3::int,NULL,NULL),
  (136::int,'Torre - Viento',FALSE::bool,3::int,NULL,NULL),
  (137::int,'Torre - Viento',FALSE::bool,3::int,NULL,NULL),
  (138::int,'Torre - Viento',FALSE::bool,3::int,NULL,NULL),
  (139::int,'Torre - Luz',FALSE::bool,3::int,NULL,NULL),
