JOIN monster_zones z ON z.name=v.zone_name
ON CONFLICT (floor_number) DO NOTHING;

-- player_tower_runs: corridas de torre infinita
CREATE TABLE IF NOT EXISTS player_tower_runs (
  id SERIAL PRIMARY KEY,
  player_id INT NOT NULL REFERENCES players(id),
  guest_player_id INT REFERENCES players(id) ON DELETE SET NULL,
  guest_player_id_2 INT REFERENCES players(id) ON DELETE SET NULL,
  current_session_id INT REFERENCES combat_sessions(id) ON DELETE SET NULL,
  difficulty INT NOT NULL DEFAULT 1,
  current_floor INT NOT NULL DEFAULT 1,
  current_room INT NOT NULL DEFAULT 1,
  coins_earned INT NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'IN_PROGRESS' CHECK (status IN ('IN_PROGRESS','EXTRACTED','WIPED')),
  started_at TIMESTAMP DEFAULT now(),
  ended_at TIMESTAMP
);

-- Fase 3: economía de la torre
ALTER TABLE players ADD COLUMN IF NOT EXISTS dungeon_coins INT NOT NULL DEFAULT 0;
ALTER TABLE player_tower_runs ADD COLUMN IF NOT EXISTS abandoned_player_ids INT[] NOT NULL DEFAULT '{}';

CREATE TABLE IF NOT EXISTS tower_vendor_shop (
  id SERIAL PRIMARY KEY,
  item_id INT NOT NULL REFERENCES items(id),
  price INT NOT NULL,
  UNIQUE(item_id)
);

INSERT INTO tower_vendor_shop(item_id, price) VALUES
  ((SELECT id FROM items WHERE code='PIEDRA_ENCANT_MAYOR'), 15),
  ((SELECT id FROM items WHERE code='PIEDRA_ENCANT_SUPREMA'), 40),
  ((SELECT id FROM items WHERE code='HUEVO_COMUN'), 12),
  ((SELECT id FROM items WHERE code='HUEVO_RARO'), 30),
  ((SELECT id FROM items WHERE code='HUEVO_EPICO'), 60)
ON CONFLICT (item_id) DO NOTHING;

CREATE TABLE IF NOT EXISTS player_tower_ready (
  player_id INT PRIMARY KEY REFERENCES players(id) ON DELETE CASCADE,
  ready_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Chat global (General / Comercio / Gremio; el de Grupo usa player_coop_group_messages)
CREATE TABLE IF NOT EXISTS chat_messages (
  id         SERIAL PRIMARY KEY,
  channel    TEXT NOT NULL CHECK (channel IN ('GENERAL','TRADE','GUILD')),
  guild_id   INT REFERENCES guilds(id) ON DELETE CASCADE,
  sender_id  INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  body       TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT chat_guild_channel_consistency CHECK (
    (channel = 'GUILD' AND guild_id IS NOT NULL) OR (channel != 'GUILD' AND guild_id IS NULL)
  )
);
CREATE INDEX IF NOT EXISTS idx_chat_messages_channel ON chat_messages(channel, id) WHERE channel != 'GUILD';
CREATE INDEX IF NOT EXISTS idx_chat_messages_guild   ON chat_messages(guild_id, id) WHERE channel = 'GUILD';

-- Mejoras de gremio: emblema/color curados, banco real y estadísticas de combate por miembro.
ALTER TABLE guilds
  ADD COLUMN IF NOT EXISTS emblem VARCHAR(8),
  ADD COLUMN IF NOT EXISTS color VARCHAR(7),
  ADD COLUMN IF NOT EXISTS bank_gold BIGINT NOT NULL DEFAULT 0;

ALTER TABLE players
  ADD COLUMN IF NOT EXISTS combat_wins INT NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS combat_losses INT NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS boss_kills INT NOT NULL DEFAULT 0;

-- Historial de actividad del gremio (join/leave/kick/promote/demote/transfer/level up/edit/banco).
CREATE TABLE IF NOT EXISTS guild_activity_log (
  id          SERIAL PRIMARY KEY,
  guild_id    INT NOT NULL REFERENCES guilds(id) ON DELETE CASCADE,
  type        VARCHAR(20) NOT NULL CHECK (type IN
    ('JOIN','LEAVE','KICK','PROMOTE','DEMOTE','TRANSFER','LEVEL_UP','EDIT','DONATION','SHOP_PURCHASE')),
  actor_id    INT REFERENCES players(id),
  target_id   INT REFERENCES players(id),
  meta        JSONB,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_guild_activity_log_guild_id ON guild_activity_log(guild_id, created_at DESC);

-- Banco de gremio: depósitos de miembros + compras en la tienda exclusiva. Sirve también como
-- log de auditoría (quién donó, quién compró qué y para quién).
CREATE TABLE IF NOT EXISTS guild_bank_transactions (
  id            SERIAL PRIMARY KEY,
  guild_id      INT NOT NULL REFERENCES guilds(id) ON DELETE CASCADE,
  player_id     INT NOT NULL REFERENCES players(id),
  type          VARCHAR(10) NOT NULL CHECK (type IN ('DEPOSIT','PURCHASE')),
  amount        INT NOT NULL,
  item_id       INT REFERENCES items(id),
  quantity      INT,
  recipient_id  INT REFERENCES players(id),
  created_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_guild_bank_tx_guild_id  ON guild_bank_transactions(guild_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_guild_bank_tx_player_id ON guild_bank_transactions(player_id, created_at DESC);

-- Contadores de jugador para requisitos de evolución de clase tipo COUNTER (ver
-- backend-spec-evolution-counters.md). _CURA_ATAQUE_ATAQUES/_CURA_ATAQUE_CURAS son sub-contadores
-- internos de CUROS_Y_ATAQUES (se resuelve como min() de ambos al chequear el requisito).
CREATE TABLE IF NOT EXISTS player_counters (
  player_id    INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  counter_code TEXT NOT NULL,
  value        INT NOT NULL DEFAULT 0,
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (player_id, counter_code)
);

-- Nigromante -> Lich (COMBATES_LIMITE_SOBREVIVIDOS): marca si algún jugador de la sesión bajó a
-- <=10% de su HP máximo en algún momento del combate. Se consume al ganar (nunca si se pierde).
ALTER TABLE combat_sessions ADD COLUMN IF NOT EXISTS had_near_death BOOLEAN NOT NULL DEFAULT FALSE;

-- Nueva rareza UNICO (drop raro a definir por el dueño del proyecto).
ALTER TABLE items DROP CONSTRAINT IF EXISTS items_rarity_check;
ALTER TABLE items ADD CONSTRAINT items_rarity_check
  CHECK (rarity IN ('COMUN', 'POCO_COMUN', 'RARO', 'EPICO', 'LEGENDARIO', 'UNICO'));

-- Renombra los counter_code que no describían la mecánica real (ya redefinidos, ver spec secciones
-- 3.3/3.4). No-op en una instalación nueva (el INSERT de arriba ya usa el nombre nuevo) — esto es
-- para renombrar en una base ya sembrada previamente (ej. producción).
UPDATE class_evolution_requirements SET counter_code = 'COMBATES_LIMITE_SOBREVIVIDOS',
  description = 'Ganar 100 combates habiendo bajado a 10% HP o menos.'
  WHERE counter_code = 'DIAS_VIVIDOS';
UPDATE class_evolution_requirements SET counter_code = 'MEDITACIONES_USADAS',
  description = '100 usos de la skill Meditación en combate.'
  WHERE counter_code = 'DIAS_MEDITANDO';


